            # -------------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path
        
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # Determine output prefix
            prefix = output_filename_prefix or Path(input_filename).stem
        
            # -------------------------------------------------------------------------
            # Windows platform guard (must be placed before any Aspose import)
            # -------------------------------------------------------------------------
            import sys
            if sys.platform != "win32":
                raise RuntimeError(
                    "aspose-page is only available on Windows (x86/x64). "
                    "This tool cannot run on Linux or macOS."
                )
        
            # -------------------------------------------------------------------------
            # Imports required for Aspose processing (lazy import inside the function)
            # -------------------------------------------------------------------------
            import logging
            from aspose.page.xps import XpsDocument, XpsLoadOptions
            from aspose.page.xps.presentation.image import TiffSaveOptions
        
            logger = logging.getLogger(__name__)
        
            try:
                # Load the XPS document
                xps_doc = XpsDocument(str(resolved_input), XpsLoadOptions())
                options = TiffSaveOptions()
                images_bytes = xps_doc.save_as_image_bytes(options)
        
                output_files: list[str] = []
                output_paths: list[str] = []
        
                for i, page_wrapper in enumerate(images_bytes):
                    # Build filename for this page
                    fname = f"{prefix}_{i + 1}.tiff"
                    fpath = get_safe_path(fname)
        
                    # Ensure the output directory exists
                    Path(fpath).parent.mkdir(parents=True, exist_ok=True)
        
                    # Write the TIFF bytes
                    with open(fpath, "wb") as f:
                        f.write(bytes(page_wrapper[0]))
        
                    output_files.append(fname)
                    output_paths.append(fpath)
        
                result = {
                    "status": "success",
                    "message": f"Converted {len(output_files)} page(s) to TIFF.",
                    "output_files": output_files,
                    "output_paths": output_paths,
                    "output_filename": output_files[0] if output_files else "",
                }
                logger.debug("page_xps_to_tiff result: %s", result)
                return result
        
            except Exception as exc:  # pragma: no cover
                logger.exception("Error in page_xps_to_tiff")
                return {"status": "error", "message": str(exc)}

