        @mcp.tool()
        async def page_eps_to_png(
            input_filename: str,
            output_filename: str | None = None,
        ) -> dict:
            """
            Convert an EPS file already stored on the server to PNG image(s).
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'logo.eps') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                input_filename: EPS filename only — e.g. 'logo.eps'.
                output_filename: Output PNG filename for single‑page EPS. None → auto‑generated.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str,               # for single‑page result
                    "output_files": list[str] | None,     # for multi‑page result (list of filenames)
                }
        
            Raises:
                FileNotFoundError: If the input EPS file does not exist.
                RuntimeError: If the code is run on a non‑Windows platform.
                Exception: Any unexpected error from Aspose is caught and returned as an error status.
            
            Example:
                result = await page_eps_to_png("logo.eps")
                # result -> {"status":"success","message":"...","output_filename":"logo.png"}
            """
            # ----------------------------------------------------------------------
            # Resolve and validate input file
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize the bare filename supplied by the caller
            input_filename = Path(input_filename.strip().replace("\x00", "")).name
            resolved_input = get_safe_path(input_filename)
            if not Path(resolved_input).is_file():
                raise FileNotFoundError(f"File not found: {input_filename}")
        
            # ----------------------------------------------------------------------
            # Windows platform guard (must be after path resolution, before Aspose import)
            # ----------------------------------------------------------------------
            import sys
        
            if sys.platform != "win32":
                raise RuntimeError(
                    "aspose-page is only available on Windows (x86/x64). "
                    "This tool cannot run on Linux or macOS."
                )
        
            # ----------------------------------------------------------------------
            # Import Aspose classes (lazy import inside the function)
            # ----------------------------------------------------------------------
            from aspose.page.eps import PsDocument
            from aspose.page.eps.device import ImageSaveOptions as EpsImageSaveOptions
        
            try:
                # Load the EPS document
                ps_doc = PsDocument(str(resolved_input))
        
                # Prepare image‑save options (True → preserve aspect ratio)
                options = EpsImageSaveOptions(True)
        
                # Convert to PNG bytes (one entry per page)
                image_bytes_list = ps_doc.save_as_image(options)
        
                # Determine output filename(s)
                if output_filename is None:
                    # Auto‑generate based on input stem
                    base_name = Path(input_filename).stem
                    output_filename = f"{base_name}.png"
                else:
                    # Sanitize user‑provided name
                    output_filename = Path(output_filename.strip().replace("\x00", "")).name
        
                # Prepare result containers
                output_files: list[str] = []
        
                if len(image_bytes_list) == 1:
                    # Single‑page EPS → one PNG file
                    resolved_output = get_safe_path(output_filename)
                    Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
                    with open(resolved_output, "wb") as f:
                        f.write(image_bytes_list[0])
                    output_files.append(output_filename)
                else:
                    # Multi‑page EPS → multiple PNG files with indexed suffix
                    prefix = Path(input_filename).stem
                    for i, img_bytes in enumerate(image_bytes_list, start=1):
                        fname = f"{prefix}_{i}.png"
                        resolved_output = get_safe_path(fname)
                        Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
                        with open(resolved_output, "wb") as f:
                            f.write(img_bytes)
                        output_files.append(fname)
        
                # Build success response
                result: dict = {
                    "status": "success",
                    "message": f"Converted {len(image_bytes_list)} page(s) to PNG.",
                    "output_filename": output_files[0] if len(output_files) == 1 else None,
                    "output_files": output_files if len(output_files) > 1 else None,
                }
                logger.debug("page_eps_to_png succeeded: %s", result)
                return result
        
            except Exception as exc:
                logger.exception("Error in page_eps_to_png")
                return {
                    "status": "error",
                    "message": str(exc),
                }

        @mcp.tool()
        async def page_create_xps(
            text: str,
            output_filename: str,
            font_size: float | None = None,
        ) -> dict:
            """
            Create a simple XPS document containing the supplied text.
        
            IMPORTANT:
            * All *_filename parameters accept ONLY the bare filename (e.g. 'scan.jpg') — no path, no directory, no drive letter, no slash.
            * The file MUST already exist in the server's ASPOSE_FILES_PATH folder before calling this tool.
            * Do NOT ask the user to upload a file — files are pre‑placed in the server folder by the user.
            * The output file is also written to the ASPOSE_FILES_PATH folder; the returned output_filename is the bare name only.
        
            Args:
                text: Text content to add to the XPS document.
                output_filename: Output XPS filename — e.g. 'output.xps'.
                font_size: Font size in points. Default: 12.0.
        
            Returns:
                dict: {
                    "status": "success" | "error",
                    "message": str,
                    "output_filename": str,   # bare name of the created file
                    "output_path": str        # absolute path on the server
                }
        
            Raises:
                ValueError: If `text` is empty.
                FileNotFoundError: If the resolved output directory cannot be created.
                RuntimeError: If the platform is not Windows.
        
            Example:
                >>> await page_create_xps("Hello, world!", "hello.xps")
                {"status":"success","message":"XPS created","output_filename":"hello.xps","output_path":"C:/aspose/files/hello.xps"}
            """
            # ----------------------------------------------------------------------
            # Resolve and sanitize output filename (no Aspose imports yet)
            # ----------------------------------------------------------------------
            from pathlib import Path
            from mcp_server.path_utils import get_safe_path, temp_output_path
            import logging
        
            logger = logging.getLogger(__name__)
        
            # sanitize filename
            output_filename = Path(output_filename.strip().replace("\x00", "")).name
        
            # Resolve to absolute safe path inside ASPOSE_FILES_PATH
            resolved_output = get_safe_path(output_filename)
        
            # Ensure the target directory exists
            Path(resolved_output).parent.mkdir(parents=True, exist_ok=True)
        
            # ----------------------------------------------------------------------
            # Windows platform guard (must be before any Aspose import)
            # ----------------------------------------------------------------------
            import sys
        
            if sys.platform != "win32":
                raise RuntimeError(
                    "aspose-page is only available on Windows (x86/x64). "
                    "This tool cannot run on Linux or macOS."
                )
        
            # ----------------------------------------------------------------------
            # Aspose imports (lazy, inside the function)
            # ----------------------------------------------------------------------
            from aspose.page.xps import XpsDocument
            import aspose.pydrawing as pyd
        
            # ----------------------------------------------------------------------
            # Core logic
            # ----------------------------------------------------------------------
            try:
                if not text:
                    raise ValueError("The 'text' parameter must not be empty.")
        
                # Determine font size
                size = float(font_size) if font_size is not None else 12.0
        
                # Create XPS document and add glyphs
                xps_doc = XpsDocument()
                glyphs = xps_doc.add_glyphs("Arial", size, pyd.FontStyle.REGULAR, 100, 200, text)
                glyphs.fill = xps_doc.create_solid_color_brush(pyd.Color.black)
        
                # Save the document
                xps_doc.save(str(resolved_output))
        
                logger.info("XPS document created: %s", resolved_output)
        
                return {
                    "status": "success",
                    "message": "XPS document created successfully.",
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                }
        
            except Exception as exc:  # pragma: no cover
                logger.error("Failed to create XPS document: %s", exc)
                return {
                    "status": "error",
                    "message": str(exc),
                    "output_filename": output_filename,
                    "output_path": str(resolved_output),
                }

